		return t.Effect == v1.TaintEffectNoSchedule || t.Effect == v1.TaintEffectNoExecute || t.Effect == v1.TaintEffectNoScheduleNoTraffic
	}'''

        if old_filter in helper_content:
            helper_content = helper_content.replace(old_filter, new_filter)
            changes_made.append("Updated DoNotScheduleTaintsFilterFunc")

            with open(taint_helper_path, 'w') as f:
                f.write(helper_content)
        else:
            errors.append(f"Could not find filter function in {taint_helper_path}")

    except Exception as e:
        errors.append(f"Error processing {taint_helper_path}: {e}")

